      "pattern": "Subject + 每天 + Time + Verb + Object",
      "structure": ["Subject", "每天", "Time", "Verb", "Object"],
      "explanation_en": "Use 'every day' to describe habitual actions. Place it before the time and verb.",
      "title": "Using 每天 for Daily Routines",
      "meaning": "Every day I do something at a certain time.",
      "when_to_use": ["Talking about daily habits", "Describing a typical day"],
      "when_not_to_use": ["For one-time events", "For past or future specific days"],
      "pragmatic_notes": "In Taiwan, 每天 is very common in small talk about routines, e.g., '你每天幾點起床？'",
      "word_order_notes": "每天 comes before the time expression and verb, not at the end.",
      "english_contrast": "In English, 'every day' can go at the beginning or end. In Chinese, it must go before the verb phrase.",
      "korean_contrast": "In Korean, '매일' can be more flexible. In Chinese, 每天 is fixed before the verb.",
      "negative_examples": [
        {
          "text": "我起床每天早上七點。",
          "error": "每天 should come before the time, not after the verb."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我每天起床早上七點。",
          "error": "Time should come after 每天 and before the verb."
        }
      ],
      "transformation_drills": ["Change '我每天喝咖啡' to negative using 不."],
      "production_drills": ["Say what you do every morning."],
      "common_error_patterns": ["Placing 每天 at the end of the sentence"],
      "repair_feedback": {
        "word_order": "Put 每天 before the time and verb.",
        "politeness": "Use 請 for polite requests, not for habits.",
        "vocabulary": "Use 每天 for every day, not 天天 in formal contexts."
      }
    },
    {
      "pattern": "Subject + Time + Verb + Object",
      "structure": ["Subject", "Time", "Verb", "Object"],
      "explanation_en": "Time expressions always come before the verb in Chinese, not at the end like in English.",
      "title": "Time Before Verb",
      "meaning": "Time must be placed before the verb.",
      "when_to_use": ["Any sentence with a time word", "Describing when an action happens"],
      "when_not_to_use": ["When time is the topic at the beginning of a sentence"],
      "pragmatic_notes": "In Taiwan, this rule is strict. Even in casual speech, time stays before the verb.",
      "word_order_notes": "Time expression immediately before the verb, after the subject.",
      "english_contrast": "English: 'I eat breakfast at 7.' Chinese: '我七點吃早餐.'",
      "korean_contrast": "Korean also places time before the verb, similar to Chinese.",
      "negative_examples": [
        {
          "text": "我吃早餐早上七點。",
          "error": "Time '早上七點' must come before the verb '吃'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我洗澡晚上。",
          "error": "Time '晚上' should be before '洗澡'."
        }
      ],
      "transformation_drills": ["Reorder '我 晚上 看電視' into correct order."],
      "production_drills": ["Say what you do at 中午."],
      "common_error_patterns": ["Putting time at the end like English"],
      "repair_feedback": {
        "word_order": "Move the time expression before the verb.",
        "politeness": "Not relevant for time order.",
        "vocabulary": "Use correct time words like 早上, 中午, 晚上."
      }
    },
    {
      "pattern": "Subject + 現在 + Verb + Object",
      "structure": ["Subject", "現在", "Verb", "Object"],
      "explanation_en": "Use 現在 to mean 'now' or 'right now'. It goes before the verb.",
      "title": "Using 現在 for Present Actions",
      "meaning": "I am doing something now.",
      "when_to_use": ["Describing current actions", "Answering 'what are you doing now?'"],
      "when_not_to_use": ["For habitual actions (use 每天)", "For future plans"],
      "pragmatic_notes": "In Taiwan, 現在 is often used with 在 to emphasize ongoing action, e.g., '我現在在看書.'",
      "word_order_notes": "現在 comes before the verb, after the subject.",
      "english_contrast": "English uses 'now' at the end or beginning. Chinese uses 現在 before the verb.",
      "korean_contrast": "Korean '지금' also goes before the verb, similar to Chinese.",
      "negative_examples": [
        {
          "text": "我吃現在早餐。",
          "error": "現在 must come before the verb '吃'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我現在早餐吃。",
          "error": "Object '早餐' should come after the verb '吃'."
        }
      ],
      "transformation_drills": ["Change '我現在看電視' to a question."],
      "production_drills": ["Say what you are doing right now."],
      "common_error_patterns": ["Putting 現在 at the end of the sentence"],
      "repair_feedback": {
        "word_order": "Place 現在 before the verb.",
        "politeness": "Use 請問 for polite questions with 現在.",
        "vocabulary": "Use 現在 for 'now', not 今天."
      }
    }
  ]
}
